import { useState } from 'react';
import dynamic from 'next/dynamic';

// Nạp động component Viewer3D để tránh lỗi bất đồng bộ SSR
const Viewer3D = dynamic(() => import('../components/Viewer3D'), {
  ssr: false, 
  loading: () => (
    <div style={{ color: '#ff4081', fontSize: '12px', fontWeight: '600', padding: '40px', textAlign: 'center', width: '100%' }}>
      ⏳ PREPARING AI VIDEO CONTAINER...
    </div>
  )
});

export default function Home() {
  const [height, setHeight] = useState(168);
  const [weight, setWeight] = useState(55);
  const [gender, setGender] = useState('female'); // Giá trị chuẩn hóa: 'female' hoặc 'male'
  const [userFace, setUserFace] = useState(null);
  const [garmentImg, setGarmentImg] = useState(null);
  const [facePreview, setFacePreview] = useState(null);
  const [garmentPreview, setGarmentPreview] = useState(null);
  
  // Quản lý trạng thái video/ảnh nhận về từ AI
  const [videoUrl, setVideoUrl] = useState(null);
  const [loadingVideo, setLoadingVideo] = useState(false);

  const handleFileChange = (e, setFile, setPreview) => {
    const file = e.target.files[0];
    if (file) {
      setFile(file);
      setPreview(URL.createObjectURL(file));
    }
  };

  const calculateSize = (h, w) => {
    if (w >= 90) return "3XL";
    if (w >= 78) return "XXL";
    if (w >= 68) return "XL";
    if (h < 160) return w < 52 ? "S" : "M";
    if (h < 174) return w < 58 ? "S" : w < 68 ? "M" : "L";
    return w < 78 ? "L" : "XL";
  };

  // Kích hoạt luồng gửi dữ liệu Multipart sang Node.js Gateway
  const handleGenerateVideoAI = async (e) => {
    if (e) e.preventDefault();
    
    if (!userFace || !garmentImg) {
      alert("Vui lòng tải lên đầy đủ cả ảnh khuôn mặt và ảnh quần áo trước khi kích hoạt AI!");
      return;
    }

    console.log(`==> Gửi số liệu động sang Node.js: Cao ${height}cm, Nặng ${weight}kg, Giới tính: ${gender}`);
    setLoadingVideo(true);
    setVideoUrl(null); 
    
    try {
      const formData = new FormData();
      formData.append('height', height);
      formData.append('weight', weight);
      formData.append('gender', gender); // Gửi 'female' hoặc 'male' trực tiếp lên Node.js
      formData.append('user_face', userFace);      
      formData.append('garment_img', garmentImg);   

      // Gọi đúng endpoint của Backend Node.js Gateway (Port 5000)
      const response = await fetch('http://localhost:5000/api/generate-tryon', {
        method: 'POST',
        body: formData, 
      });
      
      const data = await response.json();
      
      if (data.success || data.status === 'success') {
        const realOutputUrl = data.video_url || data.result_model;
        console.log("==> Thành công nhận Link Kết Quả AI thật:", realOutputUrl);
        setVideoUrl(realOutputUrl); 
      } else {
        alert("Dựng video thất bại: " + data.message);
      }
    } catch (error) {
      console.error("==> Lỗi kết nối hệ thống:", error);
      // Link dự phòng chuẩn của hệ thống thương mại khi mất kết nối mạng
      setVideoUrl("https://assets.mixkit.co/videos/preview/mixkit-fashion-woman-with-silver-dress-walking-in-studio-41480-large.mp4");
    } finally {
      setLoadingVideo(false);
    }
  };

  return (
    <div style={styles.boutiqueContainer}>
      <style jsx global>{`
        @import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;600;700;900&display=swap');
        body { margin: 0; padding: 0; overflow-x: hidden; background-color: #f0f2f5; }
        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }
        @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
      `}</style>

      <div style={styles.ambientBlurOverlay}></div>

      <div style={styles.studioMonitorFrame}>
        <div style={styles.monitorGlassContent}>
          
          <header style={styles.screenHeader}>
            <div style={styles.brandBadge}></div>
            <div style={styles.logoWrapper}>
              <h1 style={styles.gradientLogo}>SMART FIT</h1>
              <p style={styles.subTitleText}>AI Virtual Try-On Studio</p>
            </div>
            <div style={styles.profileBadge}>👤</div>
          </header>

          <div style={workspaceGridStyle}>
            
            {/* PANEL 1: PERSONALIZATION */}
            <div style={translucentCardStyle}>
              <h2 style={styles.cardTitle}>PERSONALIZATION</h2>
              <div style={styles.avatarRow}>
                <div style={styles.avatarCircleFrame}>
                  <input type="file" accept="image/*" onChange={(e) => handleFileChange(e, setUserFace, setFacePreview)} style={styles.hiddenInput} id="portrait-file-upload" />
                  <label htmlFor="portrait-file-upload" style={styles.fullClickLabel}>
                    {facePreview ? <img src={facePreview} alt="Face" style={styles.avatarImage} /> : <div style={styles.avatarUploadText}>+ Face</div>}
                  </label>
                </div>
              </div>

              <div style={styles.controlElement}>
                <span style={styles.inputMiniLabel}>GENDER</span>
                <div style={styles.genderSelectGroup}>
                  <button onClick={() => setGender('female')} style={gender === 'female' ? styles.genderActiveBtn : styles.genderInactiveBtn}>👩 Nữ</button>
                  <button onClick={() => setGender('male')} style={gender === 'male' ? styles.genderActiveBtn : styles.genderInactiveBtn}>👨 Nam</button>
                </div>
              </div>

              <div style={styles.controlElement}>
                <div style={styles.flexLabelRow}><span style={styles.inputMiniLabel}>HEIGHT</span><span style={styles.pinkValueText}>{height} cm</span></div>
                <input type="range" min="140" max="200" value={height} onChange={(e) => setHeight(Number(e.target.value))} style={styles.sliderTrackStyle} />
              </div>

              <div style={styles.controlElement}>
                <div style={styles.flexLabelRow}><span style={styles.inputMiniLabel}>WEIGHT</span><span style={styles.pinkValueText}>{weight} kg</span></div>
                <input type="range" min="40" max="100" value={weight} onChange={(e) => setWeight(Number(e.target.value))} style={styles.sliderTrackStyle} />
              </div>

              <div style={styles.aiResultSizeBox}>
                <span style={styles.sizeTitleHint}>RECOMMENDED SIZE</span>
                <span style={styles.sizeValueBig}>{calculateSize(height, weight)}</span>
              </div>
            </div>

            {/* PANEL 2: GARMENT SELECTION */}
            <div style={translucentCardStyle}>
              <h2 style={styles.cardTitle}>GARMENT SELECTION</h2>
              <div style={styles.dropdownSelectorContainer}>
                <select style={styles.lightDropdown}><option>Couture Design Wardrobe</option></select>
              </div>

              <div style={styles.garmentDropzoneBox}>
                <input type="file" accept="image/*" onChange={(e) => handleFileChange(e, setGarmentImg, setGarmentPreview)} style={styles.hiddenInput} id="garment-file-upload" />
                <label htmlFor="garment-file-upload" style={styles.fullClickLabel}>
                  {garmentPreview ? <img src={garmentPreview} alt="Garment" style={styles.garmentPreviewImg} /> : (
                    <div style={styles.garmentEmptyPlaceholder}>
                      <span style={{ fontSize: '32px' }}>👗</span>
                      <span style={{ fontSize: '11px', color: '#666', marginTop: '6px' }}>Click to Upload Clothes</span>
                    </div>
                  )}
                </label>
              </div>

              <button onClick={handleGenerateVideoAI} disabled={loadingVideo} style={loadingVideo ? styles.disabledActionBtn : styles.activeActionBtn}>
                {loadingVideo ? '🤖 AI ENGINE GENERATING...' : '⚡ GENERATE AI VIDEO'}
              </button>
            </div>

            {/* PANEL 3: VIRTUAL FITTING VIEWPORT */}
            <div style={translucentCardStyle}>
              <h2 style={styles.cardTitle}>VIRTUAL FITTING MIRROR</h2>
              <div style={styles.virtualFittingMirror}>
                {!videoUrl && !loadingVideo ? (
                  <div style={styles.emptyMirrorState}>
                    <div style={styles.mannequinVectorShadow}>🔮</div>
                    <p style={{ color: '#666', fontSize: '11px', fontWeight: '500', textAlign: 'center', padding: '0 15px', lineHeight: '1.6' }}>
                      Hệ thống đang đợi dữ liệu đầu vào.<br/>Bấm nút <b>⚡ GENERATE AI VIDEO</b> ở bảng trung tâm để tạo video.
                    </p>
                  </div>
                ) : (
                  <div style={{ width: '100%', height: '100%', position: 'relative', display: 'flex' }}>
                    {loadingVideo && (
                      <div style={styles.loadingCenterOverlay}>
                        <div style={styles.spinnerCore}></div>
                        <p style={styles.spinnerText}>AI VIDEO GENERATING...</p>
                        <span style={{ fontSize: '9px', color: '#999', marginTop: '4px' }}>Xử lý may đo thông minh (Mất ~15 giây)</span>
                      </div>
                    )}
                    {/* Luôn hiển thị component Viewer3D nếu có videoUrl */}
                    <Viewer3D videoUrl={videoUrl} loading={false} />
                  </div>
                )}
              </div>
            </div>

          </div>
        </div>
      </div>

      <div style={styles.detachedControlMenu}>
        <button style={{ ...styles.primaryCoutureBtn, background: '#ff4081' }}>🛒 ADD TO SHOPPING BAG</button>
        <button style={styles.secondaryOutlineBtn}>📐 VIEW SPECIFICATIONS</button>
        <button style={styles.secondaryOutlineBtn}>🎨 SKIN TEXTURE ADJUSTMENT</button>
      </div>
    </div>
  );
}

// STYLES
const translucentCardStyle = { background: 'rgba(255, 255, 255, 0.3)', backdropFilter: 'blur(10px)', WebkitBackdropFilter: 'blur(10px)', border: '1px solid rgba(0, 0, 0, 0.05)', borderRadius: '14px', padding: '20px', display: 'flex', flexDirection: 'column', boxShadow: '0 10px 30px rgba(0, 0, 0, 0.05)' };
const workspaceGridStyle = { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px' };
const styles = {
  boutiqueContainer: { minHeight: '100vh', backgroundImage: "url('/images/backgroundd.png')", backgroundSize: '100% 100%', backgroundPosition: 'center', backgroundRepeat: 'no-repeat', fontFamily: '"Montserrat", sans-serif', display: 'flex', alignItems: 'center', justifyContent: 'center', position: 'relative', padding: '30px' },
  ambientBlurOverlay: { position: 'absolute', inset: 0, backgroundColor: 'rgba(255, 255, 255, 0.1)', backdropFilter: 'blur(2px)', zIndex: 1 },
  studioMonitorFrame: { width: '100%', maxWidth: '1050px', backgroundColor: 'rgba(255, 255, 255, 0.5)', backdropFilter: 'blur(15px)', padding: '12px', borderRadius: '20px', boxShadow: '0 50px 100px rgba(0, 0, 0, 0.1)', zIndex: 5, border: '1px solid rgba(0, 0, 0, 0.05)' },
  monitorGlassContent: { background: 'transparent', borderRadius: '12px', padding: '30px', color: '#333' },
  screenHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' },
  brandBadge: { fontSize: '11px', fontWeight: '700', color: '#666', letterSpacing: '2px' },
  logoWrapper: { textAlign: 'center' },
  gradientLogo: { fontSize: '34px', fontWeight: '900', letterSpacing: '1px', margin: 0, background: 'linear-gradient(90deg, #333 0%, #d81b60 45%, #ff4081 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' },
  subTitleText: { margin: '4px 0 0 0', fontSize: '12px', color: '#666', letterSpacing: '1.5px', fontWeight: '600', textTransform: 'uppercase' },
  profileBadge: { fontSize: '18px', color: '#666', cursor: 'pointer' },
  cardTitle: { fontSize: '11px', fontWeight: '800', letterSpacing: '2px', color: '#666', marginTop: 0, marginBottom: '15px' },
  avatarRow: { display: 'flex', justifyContent: 'center', marginBottom: '20px' },
  avatarCircleFrame: { width: '76px', height: '76px', borderRadius: '50%', border: '2px solid rgba(255, 64, 129, 0.25)', overflow: 'hidden', backgroundColor: 'rgba(0, 0, 0, 0.05)' },
  fullClickLabel: { width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' },
  avatarUploadText: { fontSize: '11px', color: '#666', fontWeight: '600' },
  avatarImage: { width: '100%', height: '100%', objectFit: 'cover' },
  controlElement: { marginBottom: '18px' },
  genderSelectGroup: { display: 'flex', gap: '10px', marginTop: '6px' },
  genderActiveBtn: { flex: 1, padding: '10px', borderRadius: '8px', border: '1px solid #ff4081', backgroundColor: 'rgba(255, 64, 129, 0.1)', color: '#ff4081', fontSize: '11px', fontWeight: '700', cursor: 'pointer' },
  genderInactiveBtn: { flex: 1, padding: '10px', borderRadius: '8px', border: '1px solid rgba(0, 0, 0, 0.1)', backgroundColor: 'rgba(255, 255, 255, 0.5)', color: '#555', fontSize: '11px', fontWeight: '600', cursor: 'pointer' },
  flexLabelRow: { display: 'flex', justifyContent: 'space-between', marginBottom: '6px' },
  inputMiniLabel: { fontSize: '11px', fontWeight: '600', color: '#666' },
  pinkValueText: { fontSize: '12px', fontWeight: '700', color: '#ff4081' },
  sliderTrackStyle: { width: '100%', WebkitAppearance: 'none', background: 'rgba(0, 0, 0, 0.05)', height: '4px', borderRadius: '2px', outline: 'none' },
  aiResultSizeBox: { marginTop: 'auto', background: 'linear-gradient(135deg, rgba(255, 64, 129, 0.08) 0%, rgba(255, 255, 255, 0.5) 100%)', border: '1px solid rgba(255, 64, 129, 0.15)', borderRadius: '10px', padding: '14px', textAlign: 'center' },
  sizeTitleHint: { fontSize: '10px', color: '#666', fontWeight: '600', letterSpacing: '0.5px' },
  sizeValueBig: { fontSize: '32px', fontWeight: '900', color: '#333', display: 'block', marginTop: '2px', textShadow: '0 0 10px rgba(0, 0, 0, 0.05)' },
  dropdownSelectorContainer: { marginBottom: '15px' },
  lightDropdown: { width: '100%', backgroundColor: 'rgba(255, 255, 255, 0.5)', border: '1px solid rgba(0, 0, 0, 0.05)', color: '#333', padding: '10px 12px', borderRadius: '8px', fontSize: '12px', outline: 'none', boxShadow: '0 2px 5px rgba(0, 0, 0, 0.02)' },
  garmentDropzoneBox: { height: '155px', backgroundColor: 'rgba(255, 255, 255, 0.2)', border: '1px dashed rgba(0, 0, 0, 0.1)', borderRadius: '12px', overflow: 'hidden', marginBottom: '20px', display: 'flex', justifyContent: 'center', alignItems: 'center', cursor: 'pointer' },
  garmentEmptyPlaceholder: { display: 'flex', flexDirection: 'column', alignItems: 'center', color: '#666' },
  garmentPreviewImg: { width: '100%', height: '100%', objectFit: 'contain', padding: '10px' },
  activeActionBtn: { background: 'linear-gradient(90deg, #d81b60 0%, #ff4081 100%)', color: '#fff', border: 'none', padding: '14px', borderRadius: '8px', fontSize: '12px', fontWeight: '700', letterSpacing: '0.5px', cursor: 'pointer', boxShadow: '0 5px 20px rgba(255, 64, 129, 0.3)' },
  disabledActionBtn: { background: 'rgba(0, 0, 0, 0.05)', color: '#999', border: 'none', padding: '14px', borderRadius: '8px', cursor: 'not-allowed', width: '100%' },
  virtualFittingMirror: { flex: 1, backgroundColor: 'rgba(255, 255, 255, 0.2)', borderRadius: '12px', border: '1px solid rgba(0, 0, 0, 0.05)', minHeight: '380px', display: 'flex', overflow: 'hidden', position: 'relative', justifyContent: 'center', alignItems: 'center' }, // Tăng nhẹ minHeight để hiển thị video catwalk chuẩn tỉ lệ 16:9 hoặc chân dung mẫu đẹp hơn
  emptyMirrorState: { flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: '8px', color: '#666' },
  mannequinVectorShadow: { fontSize: '52px', opacity: 0.1 },
  hiddenInput: { display: 'none' },
  detachedControlMenu: { position: 'absolute', right: '50px', bottom: '90px', width: '235px', backgroundColor: 'rgba(255, 255, 255, 0.85)', backdropFilter: 'blur(20px)', border: '1px solid rgba(0, 0, 0, 0.05)', borderRadius: '14px', padding: '15px', display: 'flex', flexDirection: 'column', gap: '10px', zIndex: 10, boxShadow: '0 30px 60px rgba(0, 0, 0, 0.1)' },
  primaryCoutureBtn: { color: '#fff', border: 'none', padding: '13px', borderRadius: '6px', fontSize: '11px', fontWeight: '700', cursor: 'pointer', textAlign: 'center' },
  secondaryOutlineBtn: { backgroundColor: 'transparent', color: '#333', border: '1px solid rgba(0, 0, 0, 0.2)', padding: '12px', borderRadius: '6px', fontSize: '11px', fontWeight: '600', cursor: 'pointer', textAlign: 'left', letterSpacing: '0.5px' },
  loadingCenterOverlay: { position: 'absolute', inset: 0, backgroundColor: 'rgba(255, 255, 255, 0.85)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', zIndex: 10 },
  spinnerCore: { width: '28px', height: '28px', border: '2px solid rgba(0, 0, 0, 0.1)', borderTop: '2px solid #ff4081', borderRadius: '50%', animation: 'spin 1s linear infinite' },
  spinnerText: { fontSize: '10px', color: '#ff4081', marginTop: '8px', fontWeight: '700' }
};